body.script:
//
					const slides = document.querySelectorAll('.slide');
					const ind = document.getElementById('ind');
					let cur = 0;

					function show(i) {
						slides[cur].classList.remove('active');
						cur = ((i % slides.length) + slides.length) % slides.length;
						const slide = slides[cur];
						const iframe = slide.querySelector('iframe');
						if (!iframe.dataset.loaded) {
							iframe.src = slide.dataset.src;
							iframe.dataset.loaded = '1';
						}
						slide.classList.add('active');
						ind.textContent = slide.dataset.label;
					}

					show(0);

					document.addEventListener('keydown', e => {
						if (e.key === 'ArrowRight') show(cur + 1);
						else if (e.key === 'ArrowLeft') show(cur - 1);
					});

					let touchX = null;
					const overlay = document.getElementById('swipe-overlay');
					overlay.addEventListener('touchstart', e => {
						touchX = e.touches[0].clientX;
					}, { passive: true });
					overlay.addEventListener('touchend', e => {
						if (touchX === null) return;
						const dx = e.changedTouches[0].clientX - touchX;
						touchX = null;
						if (Math.abs(dx) < 40) return;
						show(dx < 0 ? cur + 1 : cur - 1);
					}, { passive: true });
				//

//
					const cfg              = document.getElementById('cfg').dataset;
					const INSTRUMENT       = cfg.instrument;
					const ASSET            = cfg.asset;
					const MONTHLY_INST     = cfg.monthly || '';
					const REFRESH          = parseInt(cfg.refresh, 10) * 1000;
					const ZONES_BOX_REFRESH = parseInt(cfg.zonesBoxRefresh, 10) * 1000;
					const ZONES_BOX_WINDOW_HOURS = parseInt(cfg.zonesBoxWindowHours, 10);
					const SHOW_DAILY_LINES   = cfg.showDaily !== 'false';
					const SHOW_WEEKLY_LINES  = cfg.showWeekly !== 'false';
					const SHOW_MONTHLY_LINES = cfg.showMonthly !== 'false';
					// Only true on /my/<asset> — /chart/<asset> always passes
					// show_gamma_point="false" (see _build_tv_chart_context).
					const SHOW_GAMMA_POINT = cfg.showGammaPoint === 'true';
					// Thales Forecast candle colors — user-configurable via
					// Settings → Dankbit → Thales Forecast (res.config.settings),
					// defaults are light red/green so forecast candles stay
					// easily distinguishable from the real teal/red candle series.
					const FORECAST_UP_COLOR = cfg.forecastUpColor || '#a5d6a7';
					const FORECAST_DOWN_COLOR = cfg.forecastDownColor || '#ef9a9a';
					const FORECAST_WICK_UP_COLOR = cfg.forecastWickUpColor || '#66bb6a';
					const FORECAST_WICK_DOWN_COLOR = cfg.forecastWickDownColor || '#e57373';
					// /my/<asset> is the only minimal page (candles + Gamma Tops
					// only — no Weekly/Monthly/All/Daily delta=0 lines, no zones
					// boxes/extrema), and currently the only one with Gamma
					// Tops, so this reuses that same flag rather than adding a
					// second backend-driven one; the footer (trade count/nearest
					// expiry) is untouched either way.
					const MINIMAL_CHART = SHOW_GAMMA_POINT;
					// User-toggleable via the "Lines" checkbox next to the Ruler
					// button (Delta Chart only — the Gamma Chart has its own,
					// unrelated "Gamma Tops" checkbox instead) — hides every
					// horizontal price-line indicator (delta=0 sets) and, to
					// actually cut server load rather than just hiding the result
					// client-side, makes each of their refresh*() functions skip
					// the fetch entirely while off (see onToggleLines() below).
					// refreshMonthlyDeltaZero() is the one exception — it always
					// fetches regardless, since its trade_count feeds the footer.
					// Unchecked/off by default, matching the checkbox's own
					// default (unchecked) state above.
					let SHOW_ALL_LINES = false;
					// User-toggleable via the "Zones" checkbox (Delta Chart only,
					// right after "Lines") — controls the yellow top/bottom
					// zero-crossing boxes (High Zone/Low Zone) and the teal Seller
					// Max Profit/Buyer Max Loss box (Middle Zone), i.e. everything
					// refreshZonesBoxes()/clearZonesBoxes() draw. Checked/on by
					// default (matching the checkbox's own default-checked state
					// above), since these boxes were always-on before this flag
					// existed — unchecking it stops refreshZonesBoxes() from
					// calling the server at all, purely to reduce server load.
					// This has no effect on dankbit.bands either way: get_box()
					// (which /api/zones-box/<asset> calls) never persists,
					// checked or not — only the 4-hourly compute_snapshot() cron
					// ever writes to that model.
					let SHOW_ZONES_BOXES = true;
					// User-toggleable via the "Bands" checkbox (Delta Chart
					// only — this indicator is already suppressed on DG Chart via
					// MINIMAL_CHART, so this control isn't shown there at all, see the
					// t-if on its markup). Controls only the High/Resistance + Low/Support +
					// Gamma Band lines (green/red/dashed violet) — deliberately NOT
					// the yellow/teal zones boxes, which have their own separate
					// "Zones" checkbox instead (SHOW_ZONES_BOXES above). Stops
					// refreshBands() from calling the server at all while off.
					// refreshBands() only ever reads the already-persisted
					// dankbit.bands rows (/api/bands/<asset>) — it
					// never triggers a new computation, for any expiry_index. Every
					// tracked expiry's row (see TRACKED_EXPIRY_COUNT) is computed and
					// refreshed solely by the 4-hourly compute_snapshot() cron;
					// nothing this browser does — checking this box, leaving it
					// checked, or polling while it's open — causes new extrema to be
					// computed.
					let SHOW_BANDS = false;
					// Trade window used by the yellow/teal zones boxes (Delta Chart
					// only, radio toggle next to "Bands") — 'midnight' is the
					// original since-00:00-UTC-through-now default; 'hours' switches
					// to the trailing ZONES_BOX_WINDOW_HOURS hours instead (see
					// dankbit.zones_box_window_hours setting). Only 'hours' is ever
					// sent as a query param (see refreshZonesBoxes()) — a live,
					// non-persisted override on the server side (see get_box()'s
					// hours param); the 4-hourly compute_snapshot() cron and every
					// other viewer's default midnight-based view are completely
					// unaffected either way.
					let ZONES_BOX_WINDOW_MODE = 'midnight';
					// "Gamma Tops" checkbox (Gamma Chart only) — replaces the
					// old separate "Strike Gamma"/"Strike Gamma Nearest"/
					// "Strike Gamma Weekly"/"Strike Gamma Monthly" checkboxes
					// with one: instead of drawing every strike that has
					// traded (the old light-gray-to-black gradient), this
					// draws exactly one line per scope (Nearest/Weekly/
					// Monthly/All expiries) — that scope's own single
					// highest-positive-gamma strike, via the same
					// _gamma_by_strike()-backed
					// gamma_by_strike_json/gamma_by_strike_until_json routes
					// the old checkboxes used (see refreshGammaTops below).
					// Unchecked by default.
					let SHOW_GAMMA_TOPS = false;
					const DZ_URL           = '/api/delta-zero/' + INSTRUMENT;
					const MDZ_URL          = MONTHLY_INST ? '/api/delta-zero/' + MONTHLY_INST : '';
					const ADZ_URL          = '/api/delta-zero-all/' + ASSET;
					const DZT_URL          = '/api/delta-zero-tomorrow/' + ASSET;
					const DZT2_URL         = '/api/delta-zero-day-after-tomorrow/' + ASSET;
					const SG_URL           = '/api/gamma-by-strike/' + ASSET;
					const SGW_URL          = '/api/gamma-by-strike-until/' + INSTRUMENT;
					const SGM_URL          = MONTHLY_INST ? '/api/gamma-by-strike-until/' + MONTHLY_INST : '';
					const BANDS_URL        = '/api/bands/' + ASSET;
					const ZB_URL           = '/api/zones-box/' + ASSET;
					const NEAREST_EXPIRY_URL = '/api/nearest-expiry/' + ASSET;
					const FORECAST_URL    = '/api/forecast/' + ASSET;
					// "Thales Forecast" checkbox (Delta Chart only — after
					// "Bands"; the Gamma Chart no longer has this
					// checkbox at all, so SHOW_FORECAST simply never gets
					// set true there) — unchecked by default, same server-
					// load-reducing pattern as every other optional indicator on
					// this chart.
					// Draws a fully deterministic path (see FORECAST_URL) ported
					// from Thales's own forecast-candle engine — see forecast.py.
					let SHOW_FORECAST = false;
					let   INTERVAL         = '4h';
					const klineUrl   = (iv, limit) => '/api/klines/' + ASSET + '?interval=' + iv + '&limit=' + limit;

					// Lightweight Charts has no native IANA-timezone support — it always
					// renders epoch seconds as UTC wall-clock time. To display any other
					// zone, every timestamp fed into the chart is pre-shifted by that
					// zone's current UTC offset (DST-aware, since it's computed against
					// "now"), and localization.timeFormatter below formats with
					// timeZone: 'UTC' so the shifted epoch reads as real wall-clock time.
					// The zone itself is auto-detected from the browser rather than
					// hardcoded, falling back to UTC (offset 0) if detection ever fails.
					const tzOffset = (() => {
						let zone;
						try {
							zone = Intl.DateTimeFormat().resolvedOptions().timeZone;
						} catch (e) {
							return 0;
						}
						const d = new Date();
						const utc = new Date(d.toLocaleString('en-US', { timeZone: 'UTC' }));
						const local = new Date(d.toLocaleString('en-US', { timeZone: zone }));
						return (local - utc) / 1000;
					})();

					const chart = LightweightCharts.createChart(document.getElementById('chart-container'), {
						width: window.innerWidth, height: window.innerHeight,
						layout: { background: { type: 'solid', color: '#ffffff' }, textColor: '#333333' },
						grid: { vertLines: { color: '#e8e8e8' }, horzLines: { color: '#e8e8e8' } },
						crosshair: { mode: LightweightCharts.CrosshairMode.Normal, horzLine: { labelBackgroundColor: 'blue' } },
						rightPriceScale: { borderColor: '#cccccc' },
						timeScale: { borderColor: '#cccccc', timeVisible: true, secondsVisible: false },
						localization: {
							timeFormatter: ts => new Date(ts * 1000).toLocaleString('de-DE', {
								timeZone: 'UTC',
								month: 'short', day: 'numeric',
								hour: '2-digit', minute: '2-digit',
							}),
						},
					});

					window.addEventListener('resize', () => {
						chart.resize(window.innerWidth, window.innerHeight);
					});

					const series = chart.addCandlestickSeries({
						upColor: '#26a69a', downColor: '#ef5350',
						borderVisible: false, wickUpColor: '#26a69a', wickDownColor: '#ef5350',
					});

					// Invisible helper series solely to extend the shared time axis
					// FUTURE_MARGIN_DAYS past the last real candle, with labeled tick
					// marks. Candlestick setData() silently drops OHLC-less
					// "whitespace" points (confirmed empirically — a 30-point future
					// whitespace array passed alongside real candles left
					// series.data().length unchanged), so a real, fully-valued (if
					// invisible) line series is used instead; all series on a chart
					// share one time scale, so its future points extend the same axis
					// the candlesticks are drawn on.
					const futureAxisSeries = chart.addLineSeries({
						color: 'rgba(0,0,0,0)', lineWidth: 1,
						lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});

					const highResistanceSeries    = chart.addLineSeries({ color: '#2e7d32', lineWidth: 2, lastValueVisible: false, priceLineVisible: false });
					const lowSupportSeries = chart.addLineSeries({ color: '#c62828', lineWidth: 2, lastValueVisible: false, priceLineVisible: false });
					const gammaBandSeries          = chart.addLineSeries({ color: '#c9a0dc', lineWidth: 2, lineStyle: LightweightCharts.LineStyle.Dashed, lastValueVisible: false, priceLineVisible: false });
					// Smart Role-Aware Synthetic Liquidity term-structure lines
					// (dankbit.bands.smart_liq_upper_price/smart_liq_lower_price)
					// — part of the "Bands" checkbox/refreshBands(), not a
					// separate toggle, same orange used for this indicator
					// before, dotted to stay distinct from the solid/dashed
					// lines already on this chart.
					const smartLiqUpperSeries = chart.addLineSeries({ color: '#fb8c00', lineWidth: 2, lineStyle: LightweightCharts.LineStyle.Dotted, lastValueVisible: false, priceLineVisible: false });
					const smartLiqLowerSeries = chart.addLineSeries({ color: '#fb8c00', lineWidth: 2, lineStyle: LightweightCharts.LineStyle.Dotted, lastValueVisible: false, priceLineVisible: false });

					// Zones boxes: filled rectangles marking the above-price and below-price
					// zero-crossing zones, using addBaselineSeries's flat top-line + baseValue
					// fill (the "line" is a constant top price, filled down to a constant
					// baseValue bottom price) to fake a bounded rectangle Lightweight Charts
					// has no native primitive for.
					const aboveBoxSeries = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: '#fbc02d', topFillColor1: 'rgba(251, 192, 45, 0.25)', topFillColor2: 'rgba(251, 192, 45, 0.25)',
						bottomLineColor: '#fbc02d', bottomFillColor1: 'rgba(251, 192, 45, 0.25)', bottomFillColor2: 'rgba(251, 192, 45, 0.25)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					const belowBoxSeries = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: '#fbc02d', topFillColor1: 'rgba(251, 192, 45, 0.25)', topFillColor2: 'rgba(251, 192, 45, 0.25)',
						bottomLineColor: '#fbc02d', bottomFillColor1: 'rgba(251, 192, 45, 0.25)', bottomFillColor2: 'rgba(251, 192, 45, 0.25)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					// addBaselineSeries only strokes its top edge; add a plain line series
					// for the bottom edge so both edges get the same visible border.
					const aboveBoxBottomLine = chart.addLineSeries({ color: '#fbc02d', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });
					const belowBoxBottomLine = chart.addLineSeries({ color: '#fbc02d', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });

					// Seller Max Profit / Buyer Max Loss box — same left/right time edges as the yellow
					// box above (both come from the same get_box() call for the nearest
					// expiry), teal so it stays visually distinct from yellow/violet/
					// green. setBoxData() already draws a single line instead of a box
					// when top and bottom coincide (or only one is available).
					const smpBmlBoxSeries = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: 'teal', topFillColor1: 'rgba(0, 128, 128, 0.25)', topFillColor2: 'rgba(0, 128, 128, 0.25)',
						bottomLineColor: 'teal', bottomFillColor1: 'rgba(0, 128, 128, 0.25)', bottomFillColor2: 'rgba(0, 128, 128, 0.25)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					const smpBmlBoxBottomLine = chart.addLineSeries({ color: 'teal', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });

					// Thales Forecast candles ("Thales Forecast" checkbox) —
					// Thales's deterministic forecast-candle engine (see
					// forecast.py), sourced from /api/forecast/<asset>. Light
					// red/green (user-configurable, see FORECAST_UP_COLOR etc.
					// above) so it stays easily distinguishable from the real
					// candles' own teal/red at a glance.
					const forecastSeries = chart.addCandlestickSeries({
						upColor: FORECAST_UP_COLOR, downColor: FORECAST_DOWN_COLOR, borderVisible: false,
						wickUpColor: FORECAST_WICK_UP_COLOR, wickDownColor: FORECAST_WICK_DOWN_COLOR,
						lastValueVisible: false, priceLineVisible: false,
					});

					// "Gamma Tops" lines (only on /my/<asset>, see
					// SHOW_GAMMA_POINT) — one black, lineWidth-2 price line
					// per scope (Nearest/Weekly/Monthly/All expiries),
					// marking that scope's own single highest-positive-
					// gamma strike. A scope with no strikes at all, or
					// whose highest gamma is <= 0 (nothing to mark), simply
					// contributes no line. All 4 scopes reuse the same
					// _gamma_by_strike()-backed endpoints: All (SG_URL, no
					// cutoff), Weekly (SGW_URL), Monthly (SGM_URL, skipped
					// if unconfigured), Nearest (resolved live via
					// NEAREST_EXPIRY_URL then gamma-by-strike-until).
					function gammaTop(data) {
						const strikes = data.strikes || [];
						if (!strikes.length) return null;
						const top = strikes.reduce((best, item) => (item.gamma > best.gamma ? item : best), strikes[0]);
						return top.gamma > 0 ? top : null;
					}

					// Signed leg contribution, /1e6 like the combined value —
					// unlike the Abs. lines elsewhere in this addon, sign is
					// kept (not abs()'d) here since the whole point of the
					// breakdown is showing which legs pushed gamma up vs
					// down at this strike, not just how big each one is.
					function fmtLegGamma(v) {
						const r = Math.round(v / 1e6);
						return (r >= 0 ? '+' : '') + r;
					}

					function drawGammaTopLine(top, label) {
						if (!top) return;
						gammaTopsLines.push(series.createPriceLine({
							price: top.price, color: 'black', lineWidth: 2,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black',
							title: 'Γ Top ' + label + ' +' + Math.round(top.gamma / 1e6) +
								'  LC:' + fmtLegGamma(top.long_call) + ' LP:' + fmtLegGamma(top.long_put) +
								' SC:' + fmtLegGamma(top.short_call) + ' SP:' + fmtLegGamma(top.short_put),
						}));
					}

					// "Gamma Tops" checkbox (Gamma Chart only) — single
					// checkbox replacing the old separate "Strike Gamma"/
					// "Strike Gamma Nearest"/"Strike Gamma Weekly"/"Strike
					// Gamma Monthly" checkboxes; flips SHOW_GAMMA_TOPS and
					// re-fetches all 4 scopes (or clears, if just turned
					// off).
					async function refreshGammaTops() {
						gammaTopsLines.forEach(l => series.removePriceLine(l));
						gammaTopsLines.length = 0;
						if (!SHOW_GAMMA_POINT || !SHOW_GAMMA_TOPS) return;

						const allData = await (await fetch(SG_URL)).json();
						drawGammaTopLine(gammaTop(allData), 'All');

						const weeklyData = await (await fetch(SGW_URL)).json();
						drawGammaTopLine(gammaTop(weeklyData), 'Weekly');

						if (SGM_URL) {
							const monthlyData = await (await fetch(SGM_URL)).json();
							drawGammaTopLine(gammaTop(monthlyData), 'Monthly');
						}

						const nearest = await (await fetch(NEAREST_EXPIRY_URL)).json();
						if (nearest.expiry) {
							const nearestData = await (await fetch('/api/gamma-by-strike-until/' + nearest.expiry)).json();
							drawGammaTopLine(gammaTop(nearestData), 'Nearest');
						}
					}

					function onToggleGammaTops() {
						SHOW_GAMMA_TOPS = document.getElementById('gamma-tops-toggle').checked;
						refreshGammaTops();
					}

					let priceLines    = [];
					let monthlyLines  = [];
					let allLines      = [];
					let tomorrowLines = [];
					let dayAfterTomorrowLines = [];

					function clearLines(arr) {
						arr.forEach(pl => series.removePriceLine(pl));
						arr.length = 0;
					}
					// Gamma Chart's own "Gamma Tops" line set (see
					// refreshGammaTops above) — the Delta Chart has no
					// gamma peak/bottom line indicator of its own; that
					// indicator lives only on the Gamma Chart.
					let gammaTopsLines = [];

					function setStatus(text) { document.getElementById('status').textContent = text; }

					// "UTC Now:" clock (Delta Chart only — see #utc-now-label's t-if)
					// — plain wall-clock readout, no fetch involved, ticks every
					// second independent of any REFRESH poll.
					function updateUtcNowLabel() {
						const el = document.getElementById('utc-now-label');
						if (!el) return;
						el.textContent = new Date().toISOString().slice(11, 19);
					}

					function toCandle(k) {
						return { time: Math.floor(k.t / 1000) + tzOffset, open: parseFloat(k.o), high: parseFloat(k.h), low: parseFloat(k.l), close: parseFloat(k.c) };
					}

					const TF_WINDOW = { '1h': 30, '4h': 15, '1d': 365 };
					const BARS_PER_DAY = { '1h': 24, '4h': 6, '1d': 1 };
					const INTERVAL_SECONDS = { '1h': 3600, '4h': 4 * 3600, '1d': 86400 };

					const FUTURE_MARGIN_DAYS = 5;

					// realCandles.length + futureTickCount is the current total
					// logical bar count across both series sharing the time axis —
					// tracked directly rather than re-derived from series.data(),
					// since the candlestick series' own data() only ever reflects
					// realCandles (see futureAxisSeries above).
					let realCandles = [];
					let futureTickCount = 0;

					function applyVisibleRange() {
						const days = TF_WINDOW[INTERVAL] || 21;
						const barsPerDay = BARS_PER_DAY[INTERVAL] || 24;
						const lastIndex = realCandles.length + futureTickCount - 1;
						chart.timeScale().setVisibleLogicalRange({
							from: lastIndex - days * barsPerDay,
							to:   lastIndex,
						});
					}

					function rebuildSeriesData() {
						series.setData(realCandles);

						const intervalSec = INTERVAL_SECONDS[INTERVAL] || 3600;
						const lastClose = realCandles.length ? realCandles[realCandles.length - 1].close : 0;
						const lastTime = realCandles.length
							? realCandles[realCandles.length - 1].time
							: (Math.floor(Date.now() / 1000) + tzOffset);
						const count = Math.round(FUTURE_MARGIN_DAYS * 86400 / intervalSec);
						const futureTicks = [];
						for (let i = 1; i <= count; i++) {
							futureTicks.push({ time: lastTime + i * intervalSec, value: lastClose });
						}
						futureTickCount = futureTicks.length;
						futureAxisSeries.setData(futureTicks);
					}

					async function loadCandles() {
						const resp = await (await fetch(klineUrl(INTERVAL, 500))).json();
						const klines = (resp.result || []).slice().reverse();
						realCandles = klines.map(toCandle);
						rebuildSeriesData();
						applyVisibleRange();
					}

					async function updateLatestCandle() {
						const resp = await (await fetch(klineUrl(INTERVAL, 2))).json();
						const klines = resp.result || [];
						if (!klines.length) return;
						const updated = toCandle(klines[0]);
						if (realCandles.length && realCandles[realCandles.length - 1].time === updated.time) {
							realCandles[realCandles.length - 1] = updated;
						} else {
							realCandles.push(updated);
						}
						rebuildSeriesData();
					}

					async function setTf(iv) {
						INTERVAL = iv;
						document.querySelectorAll('.tf-btn').forEach(b => b.classList.toggle('active', b.textContent === iv));
						await loadCandles();
						await refreshBands();
						await refreshZonesBoxes();
						await updateForecastVisibility();
					}

					async function refreshDeltaZero() {
						if (MINIMAL_CHART || !SHOW_ALL_LINES) return;
						const data = await (await fetch(DZ_URL)).json();
						clearLines(priceLines);
						if (!SHOW_WEEKLY_LINES) return;
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => priceLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black', title: 'Weekly',
						})));
					}

					let nearestExpiryStr = null;
					let lastTradeCount = 0;

					function updateStatusLine() {
						const expiries = [INSTRUMENT, MONTHLY_INST].filter(Boolean).join('  ·  ');
						let text = expiries + '  ·  ' + lastTradeCount + ' trades';
						if (nearestExpiryStr) text += '  ·  Nearest: ' + nearestExpiryStr;
						setStatus(text);
					}

					async function refreshMonthlyDeltaZero() {
						if (!MDZ_URL) return;
						const data = await (await fetch(MDZ_URL)).json();
						clearLines(monthlyLines);
						// Line drawing is skipped in minimal mode or with the "Lines"
						// checkbox off, but this fetch still runs — its trade_count
						// feeds the footer's "N trades", which stays on /my/<asset> too.
						if (SHOW_MONTHLY_LINES && !MINIMAL_CHART && SHOW_ALL_LINES) {
							const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
							zeros.forEach(item => monthlyLines.push(series.createPriceLine({
								price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Solid,
								axisLabelVisible: true, axisLabelColor: 'black', title: 'Monthly',
							})));
						}
						lastTradeCount = data.trade_count || 0;
						updateStatusLine();
					}

					async function refreshNearestExpiry() {
						// Cheap standalone lookup (no curve-building) — the yellow zones
						// boxes use this same nearest-active-expiry internally, but via
						// their own full computation, not this lightweight endpoint.
						const data = await (await fetch(NEAREST_EXPIRY_URL)).json();
						nearestExpiryStr = data.expiry || null;
						updateStatusLine();
					}

					async function refreshAllDeltaZero() {
						if (MINIMAL_CHART || !SHOW_ALL_LINES) return;
						const data = await (await fetch(ADZ_URL)).json();
						clearLines(allLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => allLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black', title: 'All',
						})));
					}

					async function refreshTomorrowDeltaZero() {
						if (MINIMAL_CHART || !SHOW_ALL_LINES) return;
						const data = await (await fetch(DZT_URL)).json();
						clearLines(tomorrowLines);
						if (!SHOW_DAILY_LINES) return;
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => tomorrowLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'orange', title: 'Daily (24H)',
						})));
					}

					async function refreshDayAfterTomorrowDeltaZero() {
						if (MINIMAL_CHART || !SHOW_ALL_LINES) return;
						const data = await (await fetch(DZT2_URL)).json();
						clearLines(dayAfterTomorrowLines);
						if (!SHOW_DAILY_LINES) return;
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => dayAfterTomorrowLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'orange', title: 'Daily+1 (24H)',
						})));
					}

					// "Lines" checkbox (next to Ruler) — hides every horizontal
					// price-line indicator (delta=0 sets) and stops their
					// refresh*() functions from even fetching (see SHOW_ALL_LINES
					// above), to actually cut server load rather than just hiding
					// the result. Turning off clears everything immediately rather
					// than waiting for each set's own next poll (their refresh*()
					// functions return before their own clearLines() call when
					// SHOW_ALL_LINES is false). Turning back on re-fetches
					// everything immediately for the same reason.
					// refreshMonthlyDeltaZero() is untouched here — it always
					// keeps polling regardless, for the footer's trade count.
					function onToggleLines() {
						SHOW_ALL_LINES = document.getElementById('lines-toggle').checked;
						if (SHOW_ALL_LINES) {
							refreshDeltaZero();
							refreshMonthlyDeltaZero();
							refreshAllDeltaZero();
							refreshTomorrowDeltaZero();
							refreshDayAfterTomorrowDeltaZero();
						} else {
							clearLines(priceLines);
							clearLines(monthlyLines);
							clearLines(allLines);
							clearLines(tomorrowLines);
							clearLines(dayAfterTomorrowLines);
						}
					}

					function clearBandsLines() {
						highResistanceSeries.setData([]);
						lowSupportSeries.setData([]);
						gammaBandSeries.setData([]);
						smartLiqUpperSeries.setData([]);
						smartLiqLowerSeries.setData([]);
						highResistanceSeries.setMarkers([]);
						lowSupportSeries.setMarkers([]);
						smartLiqUpperSeries.setMarkers([]);
						smartLiqLowerSeries.setMarkers([]);
					}

					async function refreshBands() {
						if (MINIMAL_CHART || !SHOW_BANDS) return;
						const data = await (await fetch(BANDS_URL)).json();
						const rows = data.bands || [];
						highResistanceSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + tzOffset, value: r.high_resistance })));
						lowSupportSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + tzOffset, value: r.low_support })));
						gammaBandSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + tzOffset, value: r.gamma_band })));
						// 0.0 means absent (see dankbit.bands' smart_liq_upper_price/
						// smart_liq_lower_price) — filtered out rather than plotted,
						// same principle setBoxData()'s "0.0 = no crossing" already
						// applies to the zones boxes, so a legless/degenerate point
						// doesn't render as a spurious price-0 dip in the line.
						const smartLiqUpperRows = rows.filter(r => r.smart_liq_upper_price);
						const smartLiqLowerRows = rows.filter(r => r.smart_liq_lower_price);
						smartLiqUpperSeries.setData(smartLiqUpperRows.map(r => ({ time: Math.floor(r.t / 1000) + tzOffset, value: r.smart_liq_upper_price })));
						smartLiqLowerSeries.setData(smartLiqLowerRows.map(r => ({ time: Math.floor(r.t / 1000) + tzOffset, value: r.smart_liq_lower_price })));

						// Per-point (not whole-line) emphasis: dominance can flip from
						// one tracked expiry to the next (e.g. upper stronger at the
						// nearest expiry, lower stronger at a further one), and
						// Lightweight Charts has no per-point lineWidth within a single
						// series — so instead of thickening the whole line, draw a
						// bigger marker dot only at the points where that side's own
						// smart_liq_upper_strength/smart_liq_lower_strength actually
						// beats its counterpart at that SAME expiry (each row compared
						// only against itself, not some single "nearest" row). size:0
						// hides the marker entirely at non-dominant points, same
						// convention the +/- markers below use.
						smartLiqUpperSeries.setMarkers(smartLiqUpperRows.map(r => ({
							time: Math.floor(r.t / 1000) + tzOffset,
							position: 'inBar',
							color: '#fb8c00',
							shape: 'circle',
							size: r.smart_liq_upper_strength > r.smart_liq_lower_strength ? 2 : 0,
						})));
						smartLiqLowerSeries.setMarkers(smartLiqLowerRows.map(r => ({
							time: Math.floor(r.t / 1000) + tzOffset,
							position: 'inBar',
							color: '#fb8c00',
							shape: 'circle',
							size: r.smart_liq_lower_strength > r.smart_liq_upper_strength ? 2 : 0,
						})));

						// +/- marker per point: whether the payoff at that
						// intersection (not the intersection's own price) sits
						// above or below the zero-payoff line — size:0 hides the
						// marker's shape glyph so only the text renders.
						highResistanceSeries.setMarkers(rows.map(r => ({
							time: Math.floor(r.t / 1000) + tzOffset,
							position: 'aboveBar',
							color: '#2e7d32',
							shape: 'circle',
							size: 0,
							text: r.high_resistance_positive ? '+' : '-',
						})));
						lowSupportSeries.setMarkers(rows.map(r => ({
							time: Math.floor(r.t / 1000) + tzOffset,
							position: 'aboveBar',
							color: '#c62828',
							shape: 'circle',
							size: 0,
							text: r.low_support_positive ? '+' : '-',
						})));
					}

					function setBoxData(boxSeries, bottomLineSeries, top, bottom, fromTime, toTime) {
						// 0.0 is the "no crossing at all" sentinel (see
						// dankbit.bands) — nothing real to draw on that edge.
						if (!top && !bottom) { boxSeries.setData([]); bottomLineSeries.setData([]); return; }
						if (top && bottom && top !== bottom) {
							boxSeries.applyOptions({ baseValue: { type: 'price', price: bottom } });
							boxSeries.setData([
								{ time: fromTime, value: top },
								{ time: toTime, value: top },
							]);
							bottomLineSeries.setData([
								{ time: fromTime, value: bottom },
								{ time: toTime, value: bottom },
							]);
							return;
						}
						// Only one edge has a crossing, or both coincide (zero-height
						// box) — can't draw a rectangle, so draw a single line at
						// whichever price we do have instead of dropping it silently.
						const price = top || bottom;
						boxSeries.setData([]);
						bottomLineSeries.setData([
							{ time: fromTime, value: price },
							{ time: toTime, value: price },
						]);
					}

					function clearZonesBoxes() {
						aboveBoxSeries.setData([]);
						belowBoxSeries.setData([]);
						aboveBoxBottomLine.setData([]);
						belowBoxBottomLine.setData([]);
						smpBmlBoxSeries.setData([]);
						smpBmlBoxBottomLine.setData([]);
					}

					async function refreshZonesBoxes() {
						if (MINIMAL_CHART || !SHOW_ZONES_BOXES) return;
						// Live lookup — computed fresh by the server on every call (see
						// dankbit.bands.get_box), not read from stored history.
						// Persisted (feeding the Bands lines' history) unless
						// ZONES_BOX_WINDOW_MODE is 'hours', in which case the ?hours=
						// override makes the server compute display-only instead — see
						// ZONES_BOX_WINDOW_MODE above.
						const url = ZONES_BOX_WINDOW_MODE === 'hours'
							? ZB_URL + '?hours=' + ZONES_BOX_WINDOW_HOURS
							: ZB_URL;
						const data = await (await fetch(url)).json();
						if (!data || data.t === undefined) {
							clearZonesBoxes();
							return;
						}
						const fromTime = Math.floor(Date.now() / 1000) + tzOffset - 10 * 86400;
						const toTime   = Math.floor(data.expiration / 1000) + tzOffset;

						const aboveTop    = Math.max(data.short_zero_above_price, data.long_zero_above_price);
						const aboveBottom = Math.min(data.short_zero_above_price, data.long_zero_above_price);
						setBoxData(aboveBoxSeries, aboveBoxBottomLine, aboveTop, aboveBottom, fromTime, toTime);

						const belowTop    = Math.max(data.short_zero_below_price, data.long_zero_below_price);
						const belowBottom = Math.min(data.short_zero_below_price, data.long_zero_below_price);
						setBoxData(belowBoxSeries, belowBoxBottomLine, belowTop, belowBottom, fromTime, toTime);

						// Seller Max Profit / Buyer Max Loss box — same fromTime/toTime as the yellow box
						// above, since both come from this same nearest-expiry get_box() call.
						const smpBmlTop    = Math.max(data.seller_max_profit, data.buyer_max_loss);
						const smpBmlBottom = Math.min(data.seller_max_profit, data.buyer_max_loss);
						setBoxData(smpBmlBoxSeries, smpBmlBoxBottomLine, smpBmlTop, smpBmlBottom, fromTime, toTime);
					}

					// "Zones" checkbox (Delta Chart only, right after "Lines") —
					// controls the yellow High Zone/Low Zone boxes and the teal
					// Middle Zone (Seller Max Profit/Buyer Max Loss) box, i.e.
					// everything refreshZonesBoxes()/clearZonesBoxes() draw.
					// Checked by default (SHOW_ZONES_BOXES starts true, matching
					// the checkbox's own default-checked state), since these boxes
					// were always shown before this checkbox existed. Stops
					// refreshZonesBoxes() from calling the server at all while off
					// (see SHOW_ZONES_BOXES above), purely to reduce server load —
					// not just hiding the result; get_box() never persists to
					// dankbit.bands regardless, so this has no effect on that
					// model either way. The 4-hourly compute_snapshot() cron is
					// untouched either way. Clears the boxes immediately
					// when switched off and re-fetches immediately when switched
					// back on.
					function onToggleZonesBoxes() {
						SHOW_ZONES_BOXES = document.getElementById('zones-boxes-toggle').checked;
						if (SHOW_ZONES_BOXES) {
							refreshZonesBoxes();
						} else {
							clearZonesBoxes();
						}
					}

					// "Bands" checkbox (Delta Chart only, next to "Zones") —
					// controls only the High/Resistance + Low/Support + Gamma Band lines
					// (green/red/dashed violet), NOT the yellow/teal zones boxes,
					// which have their own separate "Zones" checkbox instead
					// (SHOW_ZONES_BOXES/onToggleZonesBoxes() above). refreshBands()
					// only ever reads the already-persisted dankbit.bands rows
					// (/api/bands/<asset>) — it never triggers a new computation.
					// Those rows are kept fresh solely by the 4-hourly compute_snapshot()
					// cron; toggling this checkbox, or this browser polling it, has no
					// effect on when new extrema get computed. Clears the lines
					// immediately when switched off (refreshBands() returns
					// before clearing when SHOW_BANDS is false) and re-fetches
					// immediately when switched back on.
					function onToggleBands() {
						SHOW_BANDS = document.getElementById('bands-toggle').checked;
						if (SHOW_BANDS) {
							refreshBands();
						} else {
							clearBandsLines();
						}
					}

					function clearForecastLines() {
						forecastSeries.setData([]);
					}

					// The Thales Forecast candles are 4h resolution and only
					// make visual sense lined up against real 4h-spaced
					// candles, so both the checkbox and the series itself
					// are restricted to the 4h timeframe — shown/hidden by
					// updateForecastVisibility() on every timeframe switch.
					// Called from setTf()/init() on both Delta and Gamma
					// Chart (both share setTf()), but the checkbox itself
					// only exists on the Delta Chart — guarded with a null
					// check rather than assuming the element is present.
					function updateForecastVisibility() {
						const visible = INTERVAL === '4h';
						const wrap = document.getElementById('forecast-toggle-wrap');
						if (wrap) wrap.style.display = visible ? '' : 'none';
						refreshForecast();
					}

					// "Thales Forecast" checkbox (Delta Chart only) —
					// fetches /api/forecast/<asset> and draws the forecast
					// candles (see FORECAST_URL, forecastSeries above). Stops
					// fetching entirely while off, or while not on the 4h
					// timeframe (see updateForecastVisibility above), same
					// server-load-reducing pattern as every other optional
					// indicator here. Display time is NOT taken from the
					// server's `t` (an arbitrary now-relative timestamp) — it's
					// recomputed here, anchored to the same grid
					// futureAxisSeries uses for its own future ticks
					// (realCandles[last].time, stepped by intervalSec).
					// Lightweight Charts builds one shared logical time axis
					// from the union of every series' timestamps; server-
					// relative "now" timestamps almost never land on that grid,
					// so forecastSeries' points ended up alternating with
					// futureAxisSeries' ticks in the same stretch — each series
					// only getting every other logical slot, which rendered as
					// every other forecast candle missing.
					//
					// The anchor walks forward from realCandles[last].time
					// (a whole number of intervalSec steps at a time, so it
					// never leaves the grid) until it's strictly past "now"
					// — rather than assuming realCandles[last] is always
					// the current still-forming candle (one step behind
					// "now"), which would silently break if Deribit or the
					// 5s updateLatestCandle() poll ever returned a stale
					// last-closed candle instead. This guarantees the first
					// forecast candle is always the next 4h candle after
					// now, on the correct grid, regardless of which one
					// realCandles[last] actually is.
					async function refreshForecast() {
						if (!SHOW_FORECAST || INTERVAL !== '4h' || !realCandles.length) { clearForecastLines(); return; }
						const data = await (await fetch(FORECAST_URL)).json();
						const points = data.points || [];
						if (!points.length) { clearForecastLines(); return; }
						const intervalSec = INTERVAL_SECONDS[INTERVAL];
						const nowShifted = Math.floor(Date.now() / 1000) + tzOffset;
						let firstTime = realCandles[realCandles.length - 1].time;
						while (firstTime <= nowShifted) firstTime += intervalSec;
						forecastSeries.setData(points.map((p, i) => ({
							time: firstTime + i * intervalSec,
							open: p.open, high: p.high, low: p.low, close: p.close,
						})));
					}

					function onToggleForecast() {
						SHOW_FORECAST = document.getElementById('forecast-toggle').checked;
						if (SHOW_FORECAST) {
							refreshForecast();
						} else {
							clearForecastLines();
						}
					}

					// 00:00-UTC-vs-trailing-hours radio toggle for the zones boxes
					// (see ZONES_BOX_WINDOW_MODE above) — re-fetches immediately on
					// change rather than waiting for the next ZONES_BOX_REFRESH poll.
					function onZonesBoxWindowChange() {
						ZONES_BOX_WINDOW_MODE = document.getElementById('zones-box-window-hours').checked ? 'hours' : 'midnight';
						refreshZonesBoxes();
					}

					let rulerActive = false;
					let rulerPrice1 = null;
					let rulerLines  = [];

					function toggleRuler() {
						rulerActive = !rulerActive;
						document.getElementById('ruler-btn').classList.toggle('active', rulerActive);
						rulerLines.forEach(l => series.removePriceLine(l));
						rulerLines = [];
						rulerPrice1 = null;
						const info = document.getElementById('ruler-info');
						info.style.display = 'none';
						info.textContent = '';
					}

					chart.subscribeClick(param => {
						if (!rulerActive || !param.point) return;
						const price = series.coordinateToPrice(param.point.y);
						if (rulerPrice1 === null) {
							rulerPrice1 = price;
							rulerLines.push(series.createPriceLine({
								price, color: '#555', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Dashed,
								axisLabelVisible: true, axisLabelColor: 'black', title: '①',
							}));
						} else {
							rulerLines.push(series.createPriceLine({
								price, color: '#555', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Dashed,
								axisLabelVisible: true, axisLabelColor: 'black', title: '②',
							}));
							const pct = ((price - rulerPrice1) / rulerPrice1 * 100);
							const sign = pct >= 0 ? '+' : '';
							const info = document.getElementById('ruler-info');
							info.style.display = 'block';
							info.textContent = rulerPrice1.toFixed(0) + ' → ' + price.toFixed(0) + '   ' + sign + pct.toFixed(2) + '%';
							rulerPrice1 = null;
						}
					});

					async function init() {
						try { await loadCandles(); await refreshDeltaZero(); await refreshMonthlyDeltaZero(); await refreshAllDeltaZero(); await refreshTomorrowDeltaZero(); await refreshDayAfterTomorrowDeltaZero(); await refreshBands(); await refreshZonesBoxes(); await refreshNearestExpiry(); await refreshGammaTops(); await updateForecastVisibility(); }
						catch (e) { setStatus('Error: ' + e.message); }
					}
					function saveChart() {
						const canvases = document.getElementById('chart-container').querySelectorAll('canvas');
						if (!canvases.length) return;
						const w = canvases[0].width, h = canvases[0].height;
						const out = document.createElement('canvas');
						out.width = w; out.height = h;
						const ctx = out.getContext('2d');
						ctx.fillStyle = '#ffffff';
						ctx.fillRect(0, 0, w, h);
						canvases.forEach(c => ctx.drawImage(c, 0, 0));
						const a = document.createElement('a');
						a.href = out.toDataURL('image/png');
						a.download = INSTRUMENT + '_delta_' + new Date().toISOString().slice(0,16).replace('T','_') + '.png';
						a.click();
					}

					updateUtcNowLabel();
					init();
					setInterval(updateLatestCandle, 5000);
					setInterval(updateUtcNowLabel, 1000);
					setInterval(refreshDeltaZero, REFRESH);
					setInterval(refreshMonthlyDeltaZero, REFRESH);
					setInterval(refreshNearestExpiry, REFRESH);
					setInterval(refreshAllDeltaZero, REFRESH);
					setInterval(refreshTomorrowDeltaZero, REFRESH);
					setInterval(refreshDayAfterTomorrowDeltaZero, REFRESH);
					setInterval(refreshBands, REFRESH);
					setInterval(refreshZonesBoxes, ZONES_BOX_REFRESH);
					setInterval(refreshGammaTops, REFRESH);
					setInterval(refreshForecast, REFRESH);
				//
